import React, { useState, useEffect } from 'react';
import BookingsTable from '../components/BookingsTable';

const BookingsManagement = () => {
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [updatingStatus, setUpdatingStatus] = useState(null);

  useEffect(() => {
    fetchBookings();
  }, []);

  const fetchBookings = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/bookings');
      const result = await response.json();
      
      if (result.success) {
        setBookings(result.data);
      }
    } catch (error) {
      console.error('Error fetching bookings:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleStatusUpdate = async (bookingId, newStatus) => {
    setUpdatingStatus(bookingId);

    try {
      const response = await fetch(`http://localhost:5000/api/bookings/${bookingId}/status`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ status: newStatus }),
      });

      const result = await response.json();

      if (result.success) {
        setBookings(prev => 
          prev.map(booking => 
            booking.id === bookingId ? result.data : booking
          )
        );
      } else {
        alert(result.message || 'Failed to update status');
      }
    } catch (error) {
      console.error('Error updating booking status:', error);
      alert('Failed to update status');
    } finally {
      setUpdatingStatus(null);
    }
  };

  const getStats = () => {
    const total = bookings.length;
    const pending = bookings.filter(b => b.status === 'pending').length;
    const confirmed = bookings.filter(b => b.status === 'confirmed').length;
    const active = bookings.filter(b => b.status === 'active').length;
    const completed = bookings.filter(b => b.status === 'completed').length;

    return { total, pending, confirmed, active, completed };
  };

  const stats = getStats();

  return (
    <div className="section">
      <div className="section-title">
        <h2>Manage Bookings</h2>
        <p>View and manage all bike rental bookings</p>
      </div>

      {/* Statistics Cards */}
      <div className="grid grid-5" style={{ marginBottom: '2rem' }}>
        <div className="card" style={{ textAlign: 'center', padding: '1.5rem' }}>
          <h3 style={{ fontSize: '2rem', margin: 0, color: 'var(--primary-color)' }}>{stats.total}</h3>
          <p style={{ margin: 0, color: 'var(--gray-color)' }}>Total Bookings</p>
        </div>
        <div className="card" style={{ textAlign: 'center', padding: '1.5rem' }}>
          <h3 style={{ fontSize: '2rem', margin: 0, color: 'var(--warning-color)' }}>{stats.pending}</h3>
          <p style={{ margin: 0, color: 'var(--gray-color)' }}>Pending</p>
        </div>
        <div className="card" style={{ textAlign: 'center', padding: '1.5rem' }}>
          <h3 style={{ fontSize: '2rem', margin: 0, color: 'var(--accent-color)' }}>{stats.confirmed}</h3>
          <p style={{ margin: 0, color: 'var(--gray-color)' }}>Confirmed</p>
        </div>
        <div className="card" style={{ textAlign: 'center', padding: '1.5rem' }}>
          <h3 style={{ fontSize: '2rem', margin: 0, color: 'var(--success-color)' }}>{stats.active}</h3>
          <p style={{ margin: 0, color: 'var(--gray-color)' }}>Active</p>
        </div>
        <div className="card" style={{ textAlign: 'center', padding: '1.5rem' }}>
          <h3 style={{ fontSize: '2rem', margin: 0, color: 'var(--gray-color)' }}>{stats.completed}</h3>
          <p style={{ margin: 0, color: 'var(--gray-color)' }}>Completed</p>
        </div>
      </div>

      {loading ? (
        <div className="loading">
          <div className="spinner"></div>
        </div>
      ) : bookings.length > 0 ? (
        <BookingsTable 
          bookings={bookings} 
          onStatusUpdate={handleStatusUpdate}
          isUpdating={updatingStatus}
        />
      ) : (
        <div className="card" style={{ textAlign: 'center', padding: '4rem' }}>
          <h3>No Bookings Found</h3>
          <p style={{ marginBottom: '2rem' }}>There are no bookings to display at the moment.</p>
        </div>
      )}
    </div>
  );
};

export default BookingsManagement;
